    public function parse_order_status(?string $status) {
        $statuses = array(
            'open' => 'open',
            'partially_filled' => 'open',
            'filled' => 'closed',
            'cancelled' => 'canceled',
            'rejected' => 'failed',
        );
        return $this->safe_string($statuses, $status, $status);
    }

    public function map_time_in_force(?string $tifRaw) {
        $tifMap = array(
            'GTC' => 'GTC',
            'IOC' => 'IOC',
            'PO' => 'ALO',
            'POST_ONLY' => 'ALO',
            'PO_TOB' => 'TOB',
            'TOB' => 'TOB',
            'ALO' => 'ALO',
        );
        $tif = null;
        if ($tifRaw !== null) {
            $tif = strtoupper($tifRaw);
        }
        return $this->safe_string($tifMap, $tif, null);
    }

    public function map_side(string $sideRaw) {
        $sideMap = array(
            'sell' => 'ask',
            'buy' => 'bid',
        );
        return $this->safe_string($sideMap, $sideRaw, $sideRaw);
    }

    public function parse_order_type(string $status) {
        $statuses = array(
            'stop_limit' => 'limit',
            'stop_market' => 'market',
            'take_profit_limit' => 'limit',
            'stop_loss_limit' => 'limit',
            'take_profit_market' => 'market',
            'stop_loss_market' => 'market',
        );
        return $this->safe_string($statuses, $status, $status);
    }

