        //       "p" => "89501",
        //       "ip" => "89501",
        //       "lp" => "89501",
        //       "a" => "0.00012",
        //       "f" => "0.00012",
        //       "oe" => "fulfill_limit",
        //       "os" => "filled",
        //       "ot" => "limit",
        //       "sp" => null,
        //       "si" => null,
        //       "r" => false,
        //       "ct" => 1765017049008,
        //       "ut" => 1765017219639,
        //       "li" => 1559696133
        //     }
        //
        $marketId = $this->safe_string_2($order, 'symbol', 's');
        $symbol = null;
        if ($symbol !== null) {
            $market = $this->safe_market($marketId, $market);
            $symbol = $market['symbol'];
        }
        $timestamp = $this->safe_integer_2($order, 'created_at', 'ct');
        $status = $this->safe_string_2($order, 'order_status', 'os', 'open'); // open if method is fetchOpenOrders
        $side = $this->safe_string($order, 'side', 'd');
        if ($side !== null) {
            $side = ($side === 'bid') ? 'buy' : 'sell';
        }
        $totalAmount = $this->safe_string_2($order, 'initial_amount', 'a');
        $filledAmount = $this->safe_string_2($order, 'filled_amount', 'f');
        $remaining = Precise::string_sub($totalAmount, $filledAmount);
        return $this->safe_order(array(
            'info' => $order,
            'id' => $this->safe_string_2($order, 'order_id', 'i'),
            'clientOrderId' => $this->safe_string_2($order, 'client_order_id', 'I'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'lastTradeTimestamp' => null,
            'lastUpdateTimestamp' => $this->safe_integer_2($order, 'updated_at', 'ut'),
            'symbol' => $symbol,
            'type' => $this->parse_order_type($this->safe_string_lower_2($order, 'order_type', 'ot')),
            'timeInForce' => null,
            'postOnly' => null,
            'reduceOnly' => $this->safe_bool_2($order, 'reduce_only', 'r'),
            'side' => $side,
            'price' => $this->safe_string_2($order, 'price', 'lp'),
            'triggerPrice' => $this->safe_number_2($order, 'stop_price', 'sp'),
            'amount' => $totalAmount,
            'cost' => null,
            'average' => $this->safe_string_2($order, 'average_filled_price', 'p'),
            'filled' => $filledAmount,
            'remaining' => $remaining,
            'status' => $this->parse_order_status($status),
            'fee' => null,
            'trades' => null,
        ), $market);
    }

