        $timestamp = $this->safe_integer($item, 'created_at');
        $type = $this->safe_string($item, 'event_type');
        $amount = $this->safe_string($item, 'amount');
        $balance = $this->safe_string($item, 'balance');
        return $this->safe_ledger_entry(array(
            'info' => $item,
            'id' => null,
            'direction' => null,
            'account' => null,
            'referenceAccount' => null,
            'referenceId' => null,
            'type' => $this->parse_ledger_entry_type($type),
            'currency' => null,
            'amount' => $this->parse_number($amount),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'before' => null,
            'after' => $this->parse_number($balance),
            'status' => null,
            'fee' => null,
        ), $currency);
    }

    public function parse_ledger_entry_type($type) {
        $ledgerType = array(
            'subaccount_transfer' => 'transfer',
            'deposit' => 'transaction',
            'deposit_release' => 'transaction',
            'withdraw' => 'transaction',
            'trade' => 'trade',
            'market_liquidation' => 'trade',
            'backstop_liquidation' => 'trade',
            'adl_liquidation' => 'trade',
            'funding' => 'funding',
            'fee' => 'fee',
            'rebate' => 'rebate',
            'cashback' => 'cashback',
            'referral' => 'referral',
            'airdrop' => 'airdrop',
            'payout' => 'payout',
        );
        return $this->safe_string($ledgerType, $type, $type);
    }

